-items:center;gap:10px;padding:10px 12px 11px}.disc{position:relative;z-index:1;width:43px;height:43px;border-radius:999px;overflow:hidden;background:radial-gradient(circle at center,rgba(255,255,255,.96) 0 12%,rgba(203,213,225,.62) 13% 19%,transparent 20%),radial-gradient(circle at 32% 24%,rgba(255,255,255,.94),transparent 31%),conic-gradient(from 120deg,rgba(226,232,240,.48),rgba(255,255,255,.88),rgba(203,213,225,.42),rgba(248,250,252,.76),rgba(226,232,240,.48));border:1px solid rgba(190,201,214,.50);box-shadow:inset 0 1px 1px rgba(255,255,255,.82),inset 0 -2px 4px rgba(148,163,184,.11),0 1px 4px rgba(15,23,42,.04)}.disc.spinning{animation:spin 4s linear infinite}.disc:before{content:"";position:absolute;inset:8px;border-radius:999px;border:1px solid rgba(255,255,255,.56);box-shadow:0 0 0 5px rgba(148,163,184,.05),0 0 0 10px rgba(148,163,184,.035);z-index:2}.cover{position:absolute;inset:13px;z-index:3;border-radius:999px;overflow:hidden;border:1px solid rgba(255,255,255,.68);background:rgba(226,232,240,.68)}.cover:before{content:"";position:absolute;left:50%;top:50%;width:4px;height:4px;transform:translate(-50%,-50%);border-radius:999px;background:rgba(148,163,184,.48);box-shadow:0 0 8px rgba(148,163,184,.30)}.cover img{position:relative;z-index:2;width:100%;height:100%;object-fit:cover}.music-info{position:relative;z-index:1;min-width:0}.music-label{color:rgba(100,116,139,.64);font-family:Georgia,serif;font-size:11px;font-style:italic;letter-spacing:.11em;line-height:1.05;margin-bottom:2px}.music-title{color:rgba(51,65,85,.95);font-size:13.5px;font-weight:500;line-height:1.32;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.music-artist{color:rgba(100,116,139,.60);font-size:11px;line-height:1.25;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.visualizer{display:flex;align-items:end;gap:3px;height:13px;margin-top:5px;opacity:.42}.visualizer i{display:block;width:2px;height:5px;border-radius:999px;background:rgba(100,116,139,.68);transform-origin:bottom}.nocturne.is-playing .visualizer{opacity:.78}.nocturne.is-playing .visualizer i{animation:equalize .7s ease-in-out infinite}.nocturne.is-playing .visualizer i:nth-child(2){animation-duration:.58s;animation-delay:-.18s}.nocturne.is-playing .visualizer i:nth-child(3){animation-duration:.66s;animation-delay:-.32s}.nocturne.is-playing .visualizer i:nth-child(4){animation-duration:.54s;animation-delay:-.12s}.nocturne.is-playing .visualizer i:nth-child(5){animation-duration:.76s;animation-delay:-.26s}.play-btn{position:relative;z-index:5;justify-self:center;display:inline-flex;align-items:center;justify-content:center;width:34px;height:34px;border:1px solid rgba(190,201,214,.50);border-radius:999px;background:radial-gradient(circle at 32% 24%,rgba(255,255,255,.95),transparent 38%),linear-gradient(135deg,rgba(255,255,255,.80),rgba(226,232,240,.58));box-shadow:inset 0 1px 1px rgba(255,255,255,.90),inset 0 -2px 5px rgba(148,163,184,.13),0 1px 3px rgba(15,23,42,.045);color:rgba(71,85,105,.82);cursor:pointer;touch-action:manipulation;-webkit-tap-highlight-color:transparent;transition:transform .18s ease,box-shadow .18s ease,color .18s ease}.play-btn:hover{transform:scale(1.06);color:rgba(51,65,85,.96)}.play-btn svg{width:14px;height:14px;fill:currentColor}.controls{position:relative;z-index:1;grid-column:1/-1;display:grid;grid-template-columns:32px minmax(0,1fr) 34px;align-items:center;gap:7px;margin-top:8px}.time{color:rgba(100,116,139,.58);font-size:10px;font-variant-numeric:tabular-nums;text-align:center}.slider{width:100%;height:12px;background:transparent;outline:none;cursor:pointer;-webkit-appearance:none;appearance:none}.slider::-webkit-slider-runnable-track{height:2px;border-radius:999px;background:rgba(148,163,184,.24)}.slider::-webkit-slider-thumb{-webkit-appearance:none;appearance:none;width:8px;height:8px;margin-top:-3px;border-radius:999px;background:rgba(255,255,255,.96);border:1px solid rgba(148,163,184,.46);box-shadow:0 1px 3px rgba(15,23,42,.10),0 0 8px rgba(255,255,255,.62)}.slider.js-progress::-webkit-slider-runnable-track{height:3px;background:linear-gradient(90deg,rgba(100,116,139,.58) var(--progress-percent,0%),rgba(148,163,184,.22) var(--progress-percent,0%))}.volume-row{position:relative;z-index:1;grid-column:1/-1;display:grid;grid-template-columns:32px minmax(0,78px) minmax(0,1fr);align-items:center;gap:7px;margin-top:3px}.volume-label{color:rgba(100,116,139,.48);font-size:10px;letter-spacing:.08em;text-align:center}.status{justify-self:end;max-width:110px;padding:3px 7px;border-radius:999px;border:1px solid rgba(203,213,225,.46);background:rgba(255,255,255,.42);color:rgba(100,116,139,.66);font-size:9.5px;line-height:1.1;text-align:center;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}.data-poem,.data-song{display:none!important}@keyframes spin{from{transform:rotate(0)}to{transform:rotate(360deg)}}@keyframes equalize{0%,100%{height:4px}50%{height:13px}}@media(max-width:600px){body{padding:4px 6px}.nocturne{width:100%}.nocturne-summary{min-height:42px;padding:8px 13px}.nocturne-title{font-size:15.5px}.music-box{grid-template-columns:43px minmax(0,1fr) 34px;gap:9px;padding:10px 11px 11px}.disc{width:41px;height:41px}.music-title{font-size:13px}}
