<body>
<div class="nocturne nocturne-unmounted">
  <div class="nocturne-shell">
    <button type="button" class="nocturne-summary" aria-label="展开或收起播放器"><span class="nocturne-mark" aria-hidden="true"></span><span class="nocturne-head"><span class="nocturne-title">Nocturne</span><span class="nocturne-brief js-brief">Waiting</span></span><span class="nocturne-arrow" aria-hidden="true"></span></button>
    <section class="nocturne-body">
      <div class="data-poem">$1</div><div class="data-song">$2</div>
      <div class="poem-box"><div class="poem-text js-poem"></div></div>
      <div class="music-box">
        <div class="disc js-disc"><div class="cover js-cover"></div></div>
        <div class="music-info"><div class="music-label">Now Playing</div><div class="music-title js-title">Searching...</div><div class="music-artist js-artist">Music Core</div><div class="visualizer" aria-hidden="true"><i></i><i></i><i></i><i></i><i></i></div></div>
        <button type="button" class="play-btn js-play" aria-label="播放或暂停"><svg class="js-icon-play" viewBox="0 0 24 24"><polygon points="8,5 19,12 8,19"></polygon></svg><svg class="js-icon-pause" viewBox="0 0 24 24" style="display:none;"><path d="M6 4h4v16H6V4zm8 0h4v16h-4V4z"></path></svg></button>
        <div class="controls"><div class="time js-current">0:00</div><input type="range" class="slider js-progress" min="0" max="100" value="0"><div class="time js-duration">0:00</div></div>
        <div class="volume-row"><div class="volume-label">VOL</div><input type="range" class="slider js-volume" min="0" max="1" step="0.05" value="0.8"><div class="status js-status">Loading</div></div>
      </div>
      <audio class="js-audio" preload="metadata"></audio>
    </section>
  </div>
</div>
<script>
(function(){
  function resizeFrame(){try{var f=window.frameElement;if(f)f.style.height=document.body.scrollHeight+'px'}catch(e){}}
  try{new ResizeObserver(resizeFrame).observe(document.body)}catch(e){}
  setTimeout(resizeFrame,100);setInterval(resizeFrame,800);
  var mounts=document.querySelectorAll('.nocturne.nocturne-unmounted');if(!mounts.length)return;
  var root=mounts[mounts.length-1];root.classList.remove('nocturne-unmounted');
  var summaryBtn=root.querySelector('.nocturne-summary');if(summaryBtn){summaryBtn.addEventListener('click',function(){root.classList.toggle('is-open');setTimeout(resizeFrame,60)})}
  function getText(selector){var el=root.querySelector(selector);if(!el)return'';var html=el.innerHTML.replace(/<br\s*\/?>/gi,'\n').replace(/<\/p>/gi,'\n');var div=document.createElement('div');div.innerHTML=html;return(div.textContent||div.innerText||'').trim()}
  function cleanSongName(text){return String(text||'').replace(/[《》「」『』“”"']/g,'').replace(/\s+/g,' ').trim()}
  function safeAttr(text){return String(text||'').replace(/"/g,'&quot;').replace(/</g,'&lt;')}
  function formatTime(time){if(!isFinite(time)||isNaN(time))return'0:00';var min=Math.floor(time/60);var sec=Math.floor(time%60);return min+':'+(sec<10?'0':'')+sec}
  var rawPoem=getText('.data-poem');var rawSong=cleanSongName(getText('.data-song'));
  var poemEl=root.querySelector('.js-poem'),briefEl=root.querySelector('.js-brief'),titleEl=root.querySelector('.js-title'),artistEl=root.querySelector('.js-artist'),coverEl=root.querySelector('.js-cover'),audio=root.querySelector('.js-audio'),playBtn=root.querySelector('.js-play'),progress=root.querySelector('.js-progress'),volume=root.querySelector('.js-volume'),currentEl=root.querySelector('.js-current'),durationEl=root.querySelector('.js-duration'),playIcon=root.querySelector('.js-icon-play'),pauseIcon=root.querySelector('.js-icon-pause'),disc=root.querySelector('.js-disc');
  var songData=null,isPlaying=false,isSearching=false,lastError='';
  if(poemEl)poemEl.textContent=rawPoem&&!rawPoem.startsWith('$')?rawPoem:'诗意暂未抵达。';
  if(briefEl)briefEl.textContent=rawSong&&!rawSong.startsWith('$')?rawSong:'Waiting';
  if(titleEl)titleEl.textContent=rawSong&&!rawSong.startsWith('$')?rawSong:'Unknown Song';
  if(audio)audio.volume=.8;
  function setStatus(text){var el=root.querySelector('.js-status');if(el)el.textContent=text}
  function setPlayingUI(flag){isPlaying=!!flag;root.classList.toggle('is-playing',isPlaying);if(disc)disc.classList.toggle('spinning',isPlaying);if(playIcon)playIcon.style.display=isPlaying?'none':'';if(pauseIcon)pauseIcon.style.display=isPlaying?'':'none'}
  function updateProgressFill(){if(!progress||!audio)return;var dur=audio.duration||0;var cur=audio.currentTime||0;progress.style.setProperty('--progress-percent',(dur?cur/dur*100:0)+'%')}
  function waitForMusicAPI(){return new Promise(function(resolve){var tries=35;function check(){if(window.Music&&typeof window.Music.SearchMusic==='function'){resolve(true);return}if(--tries<=0){resolve(false);return}setTimeout(check,100)}check()})}
  function normalizeResult(res,name){if(!res||!res.Url)return null;return{Url:res.Url,Name:res.Name||name,Singer:res.Singer||res.Artist||'Unknown Artist',Cover:res.Cover||res.Pic||''}}
  async function searchByBundledApi(name){try{var ok=await waitForMusicAPI();if(!ok)return null;var res=await window.Music.SearchMusic(name);return normalizeResult(res,name)}catch(e){lastError='Music.js';return null}}
  async function searchByNeteaseFallback(name){try{var searchUrl='https://music.163.com/api/search/get/web?csrf_token=&s='+encodeURIComponent(name)+'&type=1&offset=0&total=true&limit=5';var r=await fetch(searchUrl);if(!r.ok)return null;var j=await r.json();var list=j&&j.result&&j.result.songs?j.result.songs:[];for(var i=0;i<list.length;i++){var s=list[i];if(!s||!s.id)continue;var artist=(s.artists||[]).map(function(a){return a.name}).filter(Boolean).join(',')||'Unknown Artist';var pic=s.album&&s.album.picId?'https://api.injahow.cn/meting/?server=netease&type=pic&id='+s.album.picId:'';return{Url:'https://api.injahow.cn/meting/?server=netease&type=url&id='+s.id,Name:s.name||name,Singer:artist,Cover:pic}}}catch(e){lastError='Fallback'}return null}
  async function resolveSong(){if(songData&&songData.Url)return songData;if(isSearching)return null;if(!rawSong||rawSong.startsWith('$')){setStatus('No Data');return null}isSearching=true;setStatus('Searching');if(artistEl)artistEl.textContent='Searching';try{var res=await searchByBundledApi(rawSong);if(!res)res=await searchByNeteaseFallback(rawSong);if(!res||!res.Url){setStatus('No Match');if(artistEl)artistEl.textContent=lastError||'No Match Found';return null}songData=res;if(titleEl)titleEl.textContent=res.Name||rawSong;if(briefEl)briefEl.textContent=res.Name||rawSong;if(artistEl)artistEl.textContent=res.Singer||'Unknown Artist';if(coverEl&&res.Cover)coverEl.innerHTML='<img src="'+safeAttr(res.Cover)+'" alt="cover">';if(audio){audio.src=res.Url;audio.load()}setStatus('Ready');resizeFrame();return res}catch(e){setStatus('Error');if(artistEl)artistEl.textContent='Search Error';return null}finally{isSearching=false}}
  if(playBtn){playBtn.addEventListener('click',async function(e){e.preventDefault();e.stopPropagation();if(!audio){setStatus('No Audio');return}var data=songData&&songData.Url?songData:await resolveSong();if(!data||!data.Url){setStatus('No Source');return}try{if(isPlaying){audio.pause();setPlayingUI(false);setStatus('Paused');return}setStatus('Loading');var p=audio.play();if(p&&typeof p.then==='function'){await p}setPlayingUI(true);setStatus('Playing')}catch(err){setPlayingUI(false);setStatus('Click Again')}})}
  if(audio){audio.addEventListener('timeupdate',function(){if(!progress)return;var dur=audio.duration||0,cur=audio.currentTime||0;progress.max=dur||100;progress.value=cur;updateProgressFill();if(currentEl)currentEl.textContent=formatTime(cur);if(durationEl)durationEl.textContent=formatTime(dur)});audio.addEventListener('loadedmetadata',function(){if(durationEl)durationEl.textContent=formatTime(audio.duration);if(progress)progress.max=audio.duration||100;updateProgressFill()});audio.addEventListener('ended',function(){setPlayingUI(false);setStatus('Ended');if(progress){progress.value=0;progress.style.setProperty('--progress-percent','0%')}});audio.addEventListener('pause',function(){if(!audio.ended)setPlayingUI(false)});audio.addEventListener('play',function(){setPlayingUI(true)});audio.addEventListener('error',function(){setPlayingUI(false);setStatus('Load Failed')})}
  if(progress){progress.addEventListener('input',function(){if(!audio)return;audio.currentTime=Number(progress.value||0);updateProgressFill()})}
  if(volume){volume.addEventListener('input',function(){if(!audio)return;audio.volume=Number(volume.value||.8)})}
  resolveSong();
})();
</script>
