  function protectInlineHtml(rawHtml){
    var tokens=[];
    var htmlCommentOrTagPattern=new RegExp('(?:'+'<!'+'--[\\s\\S]*?--'+'>)|(?:<\\/?[a-z][\\w:-]*(?:\\s[^<>]*?)?>)','gi');
