<style>
/* ───────── 星空主题（与之前完全一致）──────── */
@keyframes twinkle {
  0%, 100% { opacity: 0.28; transform: scale(1); }
  50%      { opacity: 1;   transform: scale(1.2); }
}
@keyframes twinkleSoft {
  0%, 100% { opacity: 0.4; text-shadow: 0 0 0px currentColor; }
  50%      { opacity: 1;   text-shadow: 0 0 3px currentColor; }
}
@keyframes orbitSpin {
  to { transform: rotate(360deg); }
}
@keyframes choiceFlyIn {
  to { opacity: 1; transform: translateY(0); }
}
* {
  box-sizing: border-box;
}
body {
  margin: 0;
  padding: 5px 12px;
  background: transparent;
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, "Noto Sans SC", sans-serif;
  -webkit-font-smoothing: antialiased;
}
.choice-wrap {
  --st-text: currentColor;
  --t-main: var(--st-text);
  --t-dim: color-mix(in srgb, var(--st-text) 76%, transparent);
  --t-mute: color-mix(in srgb, var(--st-text) 48%, transparent);
  --t-line: color-mix(in srgb, var(--st-text) 26%, transparent);
  --tr: .4s cubic-bezier(.33, 1, .68, 1);
  position: relative;
  width: 100%;
  margin: 8px 0;
  overflow: visible;
  border-top: none;
  border-bottom: none;
  padding: 0;
  color: var(--t-dim);
  background: none;
}
.choice-head {
  list-style: none;
  display: grid;
  grid-template-columns: 34px minmax(0, 1fr) 34px;
  align-items: center;
  min-height: 38px;
  padding: 6px 18px;
  cursor: pointer;
  user-select: none;
  color: var(--t-dim);
  background: none;
  transition: color var(--tr);
}
.choice-head::-webkit-details-marker { display: none; }
.choice-balance { visibility: hidden; }
.choice-title-box {
  grid-column: 2;
  justify-self: center;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 8px;
  min-width: 0;
}
.choice-title-box::before,
.choice-title-box::after {
  content: "";
  font-size: 13px;
  color: var(--t-dim);
  opacity: 0.8;
  animation: twinkle ease-in-out infinite;
  line-height: 1;
  background: none;
}
.choice-title-box::before {
  content: "⊹ ࣪ ˖";
  animation-duration: 2.4s;
  animation-delay: 0.1s;
  margin-right: 2px;
}
.choice-title-box::after {
  content: "˖ ࣪ ⊹";
  animation-duration: 2.2s;
  animation-delay: 0.7s;
  margin-left: 2px;
}
.choice-title {
  display: inline-flex;
  align-items: baseline;
  font-family: inherit;
  font-size: 13px;
  font-weight: 400;
  letter-spacing: 0.12em;
  line-height: 1.18;
  white-space: nowrap;
  color: var(--t-dim);
}
.choice-arrow {
  grid-column: 3;
  justify-self: center;
  width: 8px;
  height: 8px;
  border-right: 1.5px solid var(--t-mute);
  border-bottom: 1.5px solid var(--t-mute);
  transform: translateY(-2px) rotate(45deg);
  opacity: 0.64;
  transition: transform 0.22s ease, opacity 0.22s ease;
}
.choice-wrap[open] .choice-arrow {
  transform: translateY(2px) rotate(225deg);
  opacity: 0.9;
  border-color: var(--t-main);
}
.choice-body {
  position: relative;
  z-index: 1;
  padding: 0 13px 10px 13px;
}
.choice-line {
  text-align: center;
  font-size: 14px;
  color: var(--t-mute);
  opacity: 0.8;
  margin: 0 0 6px 0;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 6px;
}
.choice-line span {
  display: inline-block;
  animation: twinkleSoft ease-in-out infinite;
}
.choice-line .dot-left { animation-duration: 2.1s; animation-delay: 0s; }
.choice-line .mid-star { animation-duration: 2.8s; animation-delay: 0.45s; font-size: 1.1em; }
.choice-line .dot-right { animation-duration: 2.4s; animation-delay: 0.9s; }
.choice-options {
  display: grid;
  grid-template-columns: 1fr;
  gap: 0;
}
.choice-item {
  position: relative;
  width: 100%;
  display: grid;
  grid-template-columns: 40px minmax(0, 1fr) 24px;
  gap: 10px;
  align-items: center;
  text-align: left;
  border: none;
  border-radius: 0;
  padding: 8px 0;
  color: var(--t-dim);
  background: none;
  cursor: pointer;
  font: inherit;
  opacity: 0;
  transform: translateY(12px);
  animation: choiceFlyIn 0.45s forwards;
  border-bottom: 1px dashed var(--t-line);
  transition: background 0.18s ease, color 0.18s ease;
}
.choice-item:last-child { border-bottom: none; }
.choice-item:hover {
  background: color-mix(in srgb, var(--t-main) 4%, transparent);
  border-bottom-color: var(--t-main);
}
.choice-item:active {
  background: color-mix(in srgb, var(--t-main) 8%, transparent);
  transform: scale(0.995);
}
.choice-letter {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 36px;
  height: 36px;
  color: var(--t-dim);
  font-size: 15px;
  font-weight: 500;
  transition: color 0.2s ease;
  z-index: 1;
}
.choice-letter::before,
.choice-letter::after {
  content: none;
}
.choice-orbit {
  position: absolute;
  inset: 0;
  width: 100%;
  height: 100%;
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.3s ease;
}
.choice-orbit .orbit-ring {
  fill: none;
  stroke: var(--t-dim);
  stroke-width: 1.1;
  stroke-linecap: round;
  stroke-dasharray: 1 4.5;
}
.choice-orbit .orbit-char {
  fill: var(--t-dim);
  font-size: 10px;
  font-weight: 400;
  dominant-baseline: central;
  text-anchor: middle;
}
.choice-item:hover .choice-orbit {
  opacity: 1;
  animation: orbitSpin 9s linear infinite;
}
.choice-item:hover .choice-letter { color: var(--t-main); }
.choice-item:hover .orbit-ring { stroke: var(--t-main); }
.choice-item:hover .orbit-char { fill: var(--t-main); }
.choice-text {
  position: relative;
  z-index: 1;
  min-width: 0;
  color: var(--t-dim);
  font-size: 13px;
  line-height: 1.3;
  transition: color 0.18s ease;
}
.choice-item:hover .choice-text { color: var(--t-main); }
/* ── 右侧流星 (恢复原版SVG，精致且不重复) ── */
.choice-meteor {
  justify-self: center;
  width: 22px;
  height: 22px;
  color: var(--t-mute);
  opacity: 0.55;
  transform: rotate(-15deg);
  transition: opacity 0.2s ease, transform 0.2s ease, color 0.2s ease;
}
.choice-item:hover .choice-meteor {
  opacity: 0.9;
  transform: rotate(-15deg) scale(1.05);
  color: var(--t-main);
}
.choice-raw { display: none !important; }
@media (max-width: 600px) {
  body { padding: 4px 8px; }
  .choice-head { grid-template-columns: 28px minmax(0,1fr) 28px; min-height: 36px; padding: 7px 13px; }
  .choice-title { font-size: 12px; }
  .choice-body { padding: 0 10px 8px 10px; }
  .choice-item { grid-template-columns: 34px minmax(0,1fr) 20px; gap: 8px; padding: 7px 0; }
  .choice-letter { width: 32px; height: 32px; font-size: 14px; }
  .choice-text { font-size: 12px; line-height: 1.55; }
  .choice-meteor { width: 18px; height: 18px; }
}
</style>
</head>
