    } else if (tr) tr('/setinput ' + text);
  } catch (e) {}
}
function syncTheme() {
  try {
    var w = window.parent || window;
    var d = w.document;
    var root = d.documentElement;
    var body = d.body;
    var chatEl = d.querySelector('.mes_text') || d.querySelector('#chat') || body;
    var styles = w.getComputedStyle(root);
    var chatStyles = w.getComputedStyle(chatEl || body);
    var bodyStyles = w.getComputedStyle(body || root);
    var textColor = styles.getPropertyValue('--SmartThemeTextColor').trim();
    if (!textColor || textColor.indexOf('var(') === 0) textColor = (chatStyles && chatStyles.color) || (bodyStyles && bodyStyles.color);
    document.querySelectorAll('.choice-wrap').forEach(function(el) {
      if (textColor && textColor.indexOf('var(') !== 0) el.style.setProperty('--st-text', textColor);
      var ff = (chatStyles && chatStyles.fontFamily) || (bodyStyles && bodyStyles.fontFamily);
      if (ff) el.style.fontFamily = ff;
