      if (fw) el.style.fontWeight = fw;
      var fs = styles.getPropertyValue('--mainFontSize').trim() || (chatStyles && chatStyles.fontSize) || (bodyStyles && bodyStyles.fontSize);
      if (fs) el.style.fontSize = fs;
    });
  } catch (e) {}
