  font-family: -apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,"Noto Sans SC",sans-serif;
  -webkit-font-smoothing: antialiased;
}

.choice-wrap {
  position: relative;
  width: 100%;
  max-width: none;
  margin: 8px auto;
  overflow: hidden;
  border-radius: 17px;
  color: #334155;
  background:
    linear-gradient(135deg,rgba(255,255,255,0.82),rgba(245,247,250,0.68));
  border: 1px solid rgba(255,255,255,0.62);
  box-shadow:
    0 10px 28px rgba(15,23,42,0.10),
    inset 0 1px 0 rgba(255,255,255,0.78);
  backdrop-filter: blur(18px);
  -webkit-backdrop-filter: blur(18px);
  transition:
    box-shadow 0.25s ease,
    transform 0.25s ease,
    border-color 0.25s ease;
}

.choice-wrap::before {
  content: "";
  position: absolute;
  inset: 0;
  pointer-events: none;
  background:
    radial-gradient(circle at 18% 0%,rgba(255,255,255,0.82),transparent 34%),
    linear-gradient(110deg,transparent 0%,rgba(255,255,255,0.28) 42%,transparent 58%),
    linear-gradient(180deg,rgba(255,255,255,0.30),transparent 48%);
  opacity: 0.82;
}

.choice-wrap::after {
  content: "";
  position: absolute;
  left: 18px;
  right: 18px;
  top: 1px;
  height: 1px;
  pointer-events: none;
  background:
    linear-gradient(
      90deg,
      transparent,
      rgba(255,255,255,0.90),
      transparent
    );
  opacity: 0.8;
}

.choice-wrap:hover {
  transform: translateY(-1px);
  border-color: rgba(255,255,255,0.76);
  box-shadow:
    0 14px 34px rgba(15,23,42,0.13),
    inset 0 1px 0 rgba(255,255,255,0.84);
}

.choice-head {
  position: relative;
  z-index: 1;
  list-style: none;
  display: grid;
  grid-template-columns: 34px minmax(0,1fr) 34px;
  align-items: center;
  min-height: 44px;
  padding: 10px 18px;
  cursor: pointer;
  user-select: none;
  -webkit-tap-highlight-color: transparent;
}

.choice-head::-webkit-details-marker {
  display: none;
}

.choice-head::before {
  content: "";
  position: absolute;
  top: 0;
  bottom: 0;
  width: 120px;
  left: -140px;
  pointer-events: none;
  background:
    linear-gradient(
      105deg,
      transparent,
      rgba(255,255,255,0.45),
      transparent
    );
  opacity: 0;
}

.choice-wrap:hover .choice-head::before {
  animation: titleGlide 1.65s ease forwards;
}

.choice-balance {
  width: 18px;
  height: 18px;
  visibility: hidden;
  justify-self: center;
}

.choice-title-box {
  grid-column: 2;
  justify-self: center;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 13px;
  min-width: 0;
}

.choice-title-box::before,
.choice-title-box::after {
  content: "";
  width: clamp(26px,7vw,82px);
  height: 1px;
  background:
    linear-gradient(
      90deg,
      transparent,
      rgba(130,143,158,0.42),
      transparent
    );
  opacity: 0.82;
}

.choice-title {
  position: relative;
  display: inline-flex;
  align-items: baseline;
  justify-content: center;
  font-family:
    "Cormorant Garamond",
    "Bodoni 72",
    Didot,
    "Times New Roman",
    Georgia,
    serif;
  font-size: 18px;
  font-style: italic;
  font-weight: 300;
  letter-spacing: 0.075em;
  line-height: 1.18;
  white-space: nowrap;
  color: rgba(88,99,111,0.86);
  text-shadow:
    0 1px 0 rgba(255,255,255,0.86),
    0 6px 18px rgba(100,116,139,0.12);
}

.choice-title::after {
  content: "";
  position: absolute;
  left: 9%;
  right: 9%;
  bottom: -5px;
  height: 1px;
  background:
    linear-gradient(
      90deg,
      transparent,
      rgba(148,163,184,0.38),
      transparent
    );
  opacity: 0.72;
}

.choice-arrow {
  grid-column: 3;
  justify-self: center;
  width: 8px;
  height: 8px;
  border-right: 1.5px solid rgba(100,116,139,0.58);
  border-bottom: 1.5px solid rgba(100,116,139,0.58);
  transform: translateY(-2px) rotate(45deg);
  opacity: 0.64;
  transition:
    transform 0.22s ease,
    opacity 0.22s ease,
    border-color 0.22s ease;
  pointer-events: none;
}

.choice-wrap[open] .choice-arrow {
  transform: translateY(2px) rotate(225deg);
  opacity: 0.9;
  border-color: rgba(71,85,105,0.72);
}

.choice-body {
  position: relative;
  z-index: 1;
  padding: 0 13px 13px 13px;
}

.choice-line {
  height: 1px;
  margin: 0 3px 10px 3px;
  background:
    linear-gradient(
      90deg,
      transparent,
      rgba(148,163,184,0.18) 14%,
      rgba(148,163,184,0.42) 50%,
      rgba(148,163,184,0.18) 86%,
      transparent
    );
}

.choice-options {
  display: grid;
  grid-template-columns: 1fr;
  gap: 8px;
}

.choice-item {
  position: relative;
  width: 100%;
  display: grid;
  grid-template-columns: 31px minmax(0,1fr) 22px;
  gap: 10px;
  align-items: center;
  text-align: left;
  border: 1px solid rgba(255,255,255,0.48);
  border-radius: 13px;
