.choice-letter::before {
  content: "";
  position: absolute;
  inset: 0;
  z-index: -2;
  border-radius: 43% 57% 50% 50% / 52% 44% 56% 48%;
  background:
    radial-gradient(circle at 31% 24%,rgba(255,255,255,0.96) 0%,rgba(255,255,255,0.62) 21%,transparent 42%),
    radial-gradient(circle at 68% 76%,rgba(186,196,208,0.34),transparent 44%),
