document.addEventListener('DOMContentLoaded', function () {
  function resizeFrame() {
    try {
      var f = window.frameElement;
      if (f) f.style.height = document.body.scrollHeight + 'px';
    } catch (e) {}
  }

  try {
    new ResizeObserver(resizeFrame).observe(document.body);
  } catch (e) {}

  setTimeout(resizeFrame, 100);

  var details = document.querySelector('details');
  if (details) {
    details.addEventListener('toggle', function () {
      setTimeout(resizeFrame, 50);
    });
  }

  function injectChoice(text) {
    if (!text) return;

    try {
      var inp = window.parent.document.querySelector('#send_textarea');
      var tr = window.parent.triggerSlash;

      if (inp) {
        inp.value += text;
        inp.dispatchEvent(new Event('input', { bubbles: true }));
        inp.focus();
      } else if (tr) {
        tr('/setinput ' + text);
      }
    } catch (e) {}
  }

  document.querySelectorAll('.choice-item').forEach(function (item) {
    item.addEventListener('click', function () {
      var raw = item.querySelector('.choice-raw');
      var text = raw ? raw.value.trim() : '';

      if (!text) {
        var visible = item.querySelector('.choice-text');
        text = visible ? visible.innerText.trim() : '';
      }

      injectChoice(text);
    });
  });
});
</script>
