.dc-msg-name .dc-cs{font-size:16px;line-height:1}
/* 其余字：小字默认色 */
.dc-msg-name .dc-cn{font-size:16px;line-height:1;color:inherit}

/* 情绪标签（胶囊样式） */
.dc-msg-mood{display:inline-flex;align-items:center;align-self:flex-end;flex:0 0 auto;font-size:0.60rem;padding:1px 6px;border-radius:999px;font-weight:500;line-height:1.2;font-family:"Noto Sans SC","Source Han Sans SC",sans-serif;margin:0 0 1px}

/* === 台词文本：思源宋体 === */
.dc-msg-text{display:block;margin-top:0;font-size:14.5px;color:rgba(255,255,255,0.85);line-height:1.41;word-wrap:break-word;overflow-wrap:break-word;font-family:"Noto Serif SC","Source Han Serif SC",serif}
.dc-msg-text-content{display:inline}
.dc-msg-text-content-thought{display:inline;font-style:italic;vertical-align:baseline}

/* === 装饰大引号 / 心里话装饰符 === */
.dc-msg-quote{display:inline-block;position:relative;font-size:2.3rem;font-family:Georgia,"Times New Roman",serif;line-height:0;height:0.5em;margin-left:5px;top:0.45em;transform:scaleY(0.96);transform-origin:center bottom;overflow:visible;vertical-align:baseline;pointer-events:none;font-weight:400}
.dc-msg-quote-thought{font-size:1.4rem;top:0;line-height:1;height:auto;transform:none;font-family:Georgia,"Times New Roman",serif;font-style:normal;vertical-align:baseline}

/* === HTML 嵌入块兼容 === */
.dc-html-embed{margin:12px 0}
.dc-html-iframe{display:block;width:100%;min-height:120px;border:0;background:transparent;overflow:hidden;border-radius:12px}

/* === 颜色系统（8色） === */
.dc-c1{color:#f47b67}.dc-c2{color:#45ddc0}.dc-c3{color:#e78bff}.dc-c4{color:#f0b232}
.dc-c5{color:#58a6ff}.dc-c6{color:#ff9a76}.dc-c7{color:#7ee787}.dc-c8{color:#d2a8ff}
.dc-bg1{background:#f47b67}.dc-bg2{background:#45ddc0}.dc-bg3{background:#e78bff}.dc-bg4{background:#f0b232}
.dc-bg5{background:#58a6ff}.dc-bg6{background:#ff9a76}.dc-bg7{background:#7ee787}.dc-bg8{background:#d2a8ff}
/* 情绪标签背景（低透明度） */
.dc-mood1{background:rgba(244,123,103,0.15);color:#f47b67}
.dc-mood2{background:rgba(69,221,192,0.15);color:#45ddc0}
.dc-mood3{background:rgba(231,139,255,0.15);color:#e78bff}
.dc-mood4{background:rgba(240,178,50,0.15);color:#f0b232}
.dc-mood5{background:rgba(88,166,255,0.15);color:#58a6ff}
.dc-mood6{background:rgba(255,154,118,0.15);color:#ff9a76}
.dc-mood7{background:rgba(126,231,135,0.15);color:#7ee787}
.dc-mood8{background:rgba(210,168,255,0.15);color:#d2a8ff}

/* === Markdown 样式（旁白用） === */
.dc-narration-block strong{font-weight:700}
.dc-narration-block em{font-style:italic}
.dc-narration-block del{text-decoration:line-through;opacity:0.7}
.dc-narration-block code{background:rgba(255,255,255,0.08);padding:1px 5px;border-radius:3px;font-family:"Fira Code","Source Code Pro",monospace;font-size:0.9em}
.dc-narration-block pre{background:rgba(255,255,255,0.06);padding:10px 14px;border-radius:6px;overflow-x:auto;margin:0.5em 0}
.dc-narration-block pre code{background:none;padding:0}
.dc-narration-block blockquote{border-left:3px solid rgba(255,255,255,0.2);padding-left:12px;margin:0.5em 0;color:rgba(255,255,255,0.6)}
.dc-narration-block ul,.dc-narration-block ol{padding-left:24px;margin:0.5em 0}
.dc-narration-block li{margin:2px 0}
.dc-narration-block table{border-collapse:collapse;margin:0.5em 0;width:100%}
.dc-narration-block th,.dc-narration-block td{border:1px solid rgba(255,255,255,0.15);padding:4px 8px;text-align:left}
.dc-narration-block th{background:rgba(255,255,255,0.06)}
.dc-narration-block h1,.dc-narration-block h2,.dc-narration-block h3,.dc-narration-block h4,.dc-narration-block h5,.dc-narration-block h6{margin:0.6em 0 0.3em;font-weight:700;color:rgba(255,255,255,0.9)}
.dc-narration-block h1{font-size:1.4em}.dc-narration-block h2{font-size:1.25em}.dc-narration-block h3{font-size:1.1em}
.dc-narration-block hr{border:none;border-top:1px solid rgba(255,255,255,0.15);margin:0.8em 0}
.dc-narration-block a{color:#58a6ff;text-decoration:underline}
.dc-narration-block img{max-width:100%;border-radius:4px}
</style>
