    var min = Math.floor(sec / 60);
    var s = Math.floor(sec % 60);
    return min + ':' + (s < 10 ? '0' : '') + s;
  }

  function updateProgressFill() {
    if (!progressSlider || !audio) return;
    var dur = audio.duration || 0;
    var cur = audio.currentTime || 0;
    var percent = dur ? (cur / dur) * 100 : 0;
    progressSlider.style.setProperty('--progress-percent', percent + '%');
    progressSlider.value = cur;
  }

  function waitForMusicAPI() {
    return new Promise(function(resolve) {
      var tries = 40;
      function check() {
        if (window.Music && typeof window.Music.SearchMusic === 'function') {
          resolve(true);
        } else if (--tries <= 0) {
          resolve(false);
        } else {
          setTimeout(check, 120);
        }
      }
      check();
    });
  }

  async function searchByBundledApi(name) {
    try {
      var ok = await waitForMusicAPI();
      if (!ok) return null;
      var res = await window.Music.SearchMusic(name);
      if (res && res.Url) {
        return {
          Url: res.Url,
          Name: res.Name || name,
          Singer: res.Singer || res.Artist || '星尘歌手',
          Cover: res.Cover || res.Pic || ''
        };
      }
      return null;
    } catch(e) {
      console.warn('Music.js search error:', e);
      return null;
    }
  }

  async function searchByNeteaseFallback(name) {
    try {
      var searchUrl = 'https://music.163.com/api/search/get/web?csrf_token=&s=' + encodeURIComponent(name) + '&type=1&offset=0&total=true&limit=5';
      var r = await fetch(searchUrl);
      if (!r.ok) return null;
      var j = await r.json();
      var songs = (j && j.result && j.result.songs) ? j.result.songs : [];
      for (var i = 0; i < songs.length; i++) {
        var s = songs[i];
        if (!s || !s.id) continue;
        var artist = (s.artists || []).map(function(a) { return a.name; }).filter(Boolean).join(', ') || '未知艺人';
        var pic = (s.album && s.album.picId) ? ('https://api.injahow.cn/meting/?server=netease&type=pic&id=' + s.album.picId) : '';
        return {
          Url: 'https://api.injahow.cn/meting/?server=netease&type=url&id=' + s.id,
          Name: s.name || name,
          Singer: artist,
          Cover: pic
        };
      }
      return null;
    } catch(e) {
      console.warn('Fallback search error:', e);
      return null;
    }
  }

  async function resolveSong() {
    if (songData && songData.Url) return songData;
    if (isSearching) return null;
    if (!rawSongName) {
      setStatus('无曲目');
      return null;
    }
    isSearching = true;
    setStatus('✨ 星寻 ✨');
    try {
      var res = await searchByBundledApi(rawSongName);
      if (!res) res = await searchByNeteaseFallback(rawSongName);
      if (!res || !res.Url) {
        setStatus('未寻得');
        trackArtistSpan.textContent = '未找到音源';
        return null;
      }
      songData = res;
      trackTitleSpan.textContent = res.Name || rawSongName;
      trackArtistSpan.textContent = res.Singer || '星河吟游';

      // 安全设置封面（避免 onerror 字符串拼接导致错误）
      if (coverMiniDiv) {
        if (res.Cover && res.Cover !== '') {
          var img = document.createElement('img');
          img.src = res.Cover;
          img.alt = 'cover';
          img.onerror = function() {
            this.onerror = null;
            coverMiniDiv.innerHTML = '<div class="no-cover">⊹</div>';
          };
          coverMiniDiv.innerHTML = '';
          coverMiniDiv.appendChild(img);
        } else {
          coverMiniDiv.innerHTML = '<div class="no-cover">✨</div>';
        }
      }

      if (audio) {
        audio.src = res.Url;
        audio.load();
      }
      setStatus('♫ 可奏 ♫');
      return res;
    } catch(e) {
      console.error('resolveSong error:', e);
      setStatus('检索失败');
      return null;
    } finally {
      isSearching = false;
    }
  }

  async function onPlayPause() {
    if (!audio) return;
    var data = (songData && songData.Url) ? songData : await resolveSong();
    if (!data || !data.Url) {
      setStatus('无可用音轨');
      return;
    }
    try {
      if (isPlaying) {
        audio.pause();
        setPlayingUI(false);
        setStatus('⏸ 暂歇');
      } else {
        setStatus('✨ 唤醒星声 ✨');
        await audio.play();
        setPlayingUI(true);
        setStatus('⋆ 星河漫游 ⋆');
      }
    } catch(err) {
      console.warn('play error:', err);
      setPlayingUI(false);
      setStatus('点击重试');
    }
  }

  // ---------- 事件绑定 ----------
  if (playBtn) {
    playBtn.addEventListener('click', function(e) {
      e.preventDefault();
      onPlayPause();
    });
  }

  if (audio) {
    audio.addEventListener('timeupdate', function() {
      if (!progressSlider) return;
      var cur = audio.currentTime || 0;
      var dur = audio.duration || 0;
      progressSlider.max = dur || 100;
      progressSlider.value = cur;
      updateProgressFill();
      if (currentTimeSpan) currentTimeSpan.textContent = formatTime(cur);
      if (durationSpan && dur) durationSpan.textContent = formatTime(dur);
    });

    audio.addEventListener('loadedmetadata', function() {
      if (durationSpan) durationSpan.textContent = formatTime(audio.duration);
      if (progressSlider) progressSlider.max = audio.duration || 100;
      updateProgressFill();
    });

    audio.addEventListener('ended', function() {
      setPlayingUI(false);
      setStatus('终曲 · 余音');
      if (progressSlider) progressSlider.value = 0;
      progressSlider.style.setProperty('--progress-percent', '0%');
    });

    audio.addEventListener('pause', function() {
      if (!audio.ended) setPlayingUI(false);
    });

    audio.addEventListener('play', function() {
      setPlayingUI(true);
    });

    audio.addEventListener('error', function(e) {
      console.error('audio error:', e);
      setPlayingUI(false);
      setStatus('加载失败');
    });
  }

  if (progressSlider) {
    progressSlider.addEventListener('input', function() {
      if (!audio) return;
      var val = parseFloat(this.value);
      if (!isNaN(val)) audio.currentTime = val;
      updateProgressFill();
    });
  }

  if (volumeSlider) {
    volumeSlider.addEventListener('input', function() {
      if (audio) audio.volume = parseFloat(this.value);
    });
    if (audio) audio.volume = parseFloat(volumeSlider.value) || 0.7;
  }

  // 预加载歌曲信息（不影响界面）
  resolveSong().catch(function(e) { console.warn('preload resolveSong error', e); });

  // ---------- 折叠展开时重新计算高度 ----------
  var detailsEl = document.querySelector('.starry-player');
  if (detailsEl) {
    detailsEl.addEventListener('toggle', function() {
      setTimeout(resizeFrame, 60);
    });
  }

  // ---------- 启动主题同步与高度观察 ----------
  syncTheme();
  try {
    var w = window.parent;
    var d = w.document;
    if (d && window.MutationObserver) {
      var observer = new MutationObserver(syncTheme);
      observer.observe(d.documentElement, { attributes: true, attributeFilter: ['style', 'class'] });
      if (d.body) observer.observe(d.body, { attributes: true, attributeFilter: ['style', 'class'] });
    }
    setInterval(syncTheme, 1500);
  } catch(e) {}

  try {
    new ResizeObserver(resizeFrame).observe(document.body);
  } catch(e) {}
  setTimeout(resizeFrame, 120);
})();
</script>
</body>
</html>
