    padding: 28px 20px 20px 20px !important;

    /* 🔥 砍掉了这里原有的杂乱蓝条，只保留纯粹干净的暗色深坑渐变 */
    background: linear-gradient(145deg, #161922 0%, #0d0f14 100%) !important; 

