      if (/角色脚本|角色可用|当前角色|局部脚本/.test(text)) return "scoped";
      if (/预设脚本|绑定到当前预设|当前预设/.test(text)) return "preset";
      if (/全局脚本|酒馆全局可用/.test(text)) return "global";
      return "global";
