                     <button class="visual-pick-btn" data-target="${ID}-rec-off-${key}" style="background: rgba(96,185,200,0.3); border: none; color: white; border-radius: 4px; padding: 4px; font-size: 10px; cursor: pointer;">🔍</button>
                   </div>
