               modelSection.appendChild(recWrapper);
            }

            renderModelSegments();
            attachModelEventHandlers();
            attachRecToggleHandler();
          }

          pdoc.querySelectorAll(`#${ID} [contenteditable]`).forEach(el => el.removeAttribute("contenteditable"));
