               newBtn.appendChild(tools);

               let container = targetGroupForAdd.classList?.contains("layout-subgroup") ? targetGroupForAdd.querySelector(":scope > .grid-toggles") : targetGroupForAdd.querySelector(":scope > .grid-toggles");
