          // Disable edit mode tools for the Recommended item toggle
          if (btn.id === `${ID}-rec-toggle`) {
             tools.innerHTML = `<button class="edit-btn model-cfg-btn" title="配置核心模型">⚙️配置推荐条目</button>`;
